Examples.Code:
### List corpora
# @name listCorpora
GET {{host}}/v2/corpora?limit=10&filter=Vectara Content&corpus_id=["crp_12345"]&page_key={{page_key}}
x-api-key: {{api_key}}
Authorization: Bearer {{token}}
Request-Timeout: {{Request-Timeout}}
Request-Timeout-Millis: {{Request-Timeout-Millis}}
Accept: application/json

## Responses
# 200
# Description: The response includes an array of `corpora` objects with matching `corpora` and `metadata`.
# Content-Type: application/json
# 403
# Description: Permissions do not allow listing corpora.
# Content-Type: application/json

### Update document, merging the metadata.
# @name updateCorpusDocument
PATCH {{host}}/v2/corpora/{{corpus_key}}/documents/{{document_id}}
x-api-key: {{api_key}}
Authorization: Bearer {{token}}
Request-Timeout: {{Request-Timeout}}
Request-Timeout-Millis: {{Request-Timeout-Millis}}
Content-Type: application/json
Accept: application/json

{
  "metadata": {
    "title": "2024 ESG Annual Report \u2013 EuroBank",
    "region": "EU",
    "industry": "banking",
    "year": 2024
  }
}

## Responses
# 200
# Description: Successfully updated the document.
# Content-Type: application/json
# 403
# Description: Permissions do not allow updating a document in the corpus.
# Content-Type: application/json
# 404
# Description: Corpus or document not found.
# Content-Type: application/json
# 429
# Description: Too many concurrent requests. Please retry.
# Content-Type: application/json

