### Multiple Corpora Query
# @name query
POST {{host}}/v2/query
x-api-key: {{api_key}}
Authorization: Bearer {{token}}
Request-Timeout: {{Request-Timeout}}
Request-Timeout-Millis: {{Request-Timeout-Millis}}
Content-Type: application/json
Accept: application/json, text/event-stream

{
  "query": "Compare RSU vesting schedules in 2022 vs. 2024 equity policies for Canadian tech employees.",
  "search": {
    "corpora": [
      {
        "corpus_key": "fin_docs",
        "metadata_filter": "doc.type = \u0027equity_policy\u0027 AND doc.country = \u0027CA\u0027 AND (doc.year = 2022 OR doc.year = 2024)",
        "lexical_interpolation": 0.005,
        "limit": 50
      }
    ],
    "context_configuration": {
      "sentences_before": 2,
      "sentences_after": 2,
      "start_tag": "\u003Cem\u003E",
      "end_tag": "\u003C/em\u003E"
    },
    "reranker": {
      "type": "customer_reranker",
      "reranker_name": "Rerank_Multilingual_v1",
      "limit": 50,
      "include_context": true
    }
  },
  "generation": {
    "generation_preset_name": "mockingbird-2.0",
    "prompt_template": "[{\u0022role\u0022: \u0022system\u0022, \u0022content\u0022: \u0022You are an HR policy analyst.\u0022}, #foreach ($qResult in $vectaraQueryResults) {\u0022role\u0022: \u0022user\u0022, \u0022content\u0022: \u0022Evaluate the $vectaraIdxWord[$foreach.index] RSU vesting schedule for Canadian employees.\u0022}, {\u0022role\u0022: \u0022assistant\u0022, \u0022content\u0022: \u0022${qResult.getText()}\u0022}, #end {\u0022role\u0022: \u0022user\u0022, \u0022content\u0022: \u0022Compare RSU vesting schedules for 2022 and 2024 policies in Canada.\u0022}]",
    "max_used_search_results": 8,
    "response_language": "eng",
    "enable_factual_consistency_score": true
  },
  "save_history": true,
  "intelligent_query_rewriting": false
}

## Responses
# 200
# Description: A response to a query.
# Content-Type: application/json, text/event-stream
# 400
# Description: Query request was malformed.
# Content-Type: application/json
# 403
# Description: Permissions do not allow querying one or more corpora in the request.
# Content-Type: application/json
# 404
# Description: One or more of the corpora were not found.
# Content-Type: application/json
